create table atendentes (ativo boolean not null, created_at timestamp(6) not null, id bigserial not null, updated_at timestamp(6), version bigint, telefone varchar(20), created_by varchar(100), email varchar(100) not null unique, modified_by varchar(100), nome varchar(100) not null, senha varchar(255) not null, tipo_usuario varchar(255) not null check (tipo_usuario in ('CLIENTE','ATENDENTE','COZINHA','GERENTE','ADMIN')), primary key (id));
create table clientes (ativo boolean not null, telefone_verificado boolean not null, created_at timestamp(6) not null, id bigserial not null, otp_expiration timestamp(6), updated_at timestamp(6), version bigint, otp_code varchar(10), telefone varchar(20) not null unique, created_by varchar(100), modified_by varchar(100), nome varchar(100), tipo_usuario varchar(255) not null check (tipo_usuario in ('CLIENTE','ATENDENTE','COZINHA','GERENTE','ADMIN')), primary key (id));
create table configuracao_financeira_event_log (flag_anterior boolean, flag_novo boolean, valor_anterior numeric(14,2), valor_novo numeric(14,2), entidade_id bigint, id bigserial not null, timestamp timestamp(6) not null, usuario_role varchar(50) not null, entidade_tipo varchar(60), tipo_evento varchar(60) not null, usuario_nome varchar(100) not null, detalhe varchar(500), motivo varchar(500), primary key (id));
create table configuracao_financeira_sistema (limite_pos_pago numeric(10,2) not null, pos_pago_ativo boolean not null, valor_minimo_operacao numeric(10,2) not null, created_at timestamp(6) not null, id bigserial not null, updated_at timestamp(6), version bigint, atualizado_por_role varchar(50), atualizado_por_nome varchar(100), created_by varchar(100), modified_by varchar(100), motivo_ultima_alteracao varchar(500), primary key (id));
create table cozinhas (ativa boolean not null, created_at timestamp(6) not null, id bigserial not null, updated_at timestamp(6), version bigint, tipo varchar(30) not null check (tipo in ('CENTRAL','BAR_PREP','CONFEITARIA','GRILL','PIZZARIA','SUSHI','ESPECIAL')), impressora_id varchar(50), created_by varchar(100), modified_by varchar(100), nome varchar(100) not null, descricao varchar(500), primary key (id));
create table eventos_sessao (created_at timestamp(6) not null, id bigserial not null, sessao_consumo_id bigint not null, updated_at timestamp(6), version bigint, tipo_evento varchar(50) not null check (tipo_evento in ('SESSAO_ABERTA','MESA_VINCULADA','MESA_DESVINCULADA','CLIENTE_VINCULADO','PEDIDO_CRIADO','FUNDO_RECARREGADO','FUNDO_DEBITADO','PAGAMENTO_SOLICITADO','SESSAO_ENCERRADA','SESSAO_EXPIRADA_AUTOMATICAMENTE','OUTRO')), created_by varchar(100), modified_by varchar(100), descricao TEXT, usuario_responsavel varchar(255), primary key (id));
create table fundos_consumo (ativo boolean not null, saldo_atual numeric(19,2), created_at timestamp(6) not null, id bigserial not null, sessao_consumo_id bigint not null unique, updated_at timestamp(6), version bigint, created_by varchar(100), modified_by varchar(100), primary key (id));
create table instituicoes (ativa boolean not null, created_at timestamp(6) not null, id bigserial not null, otp_expiration timestamp(6), tenant_id bigint not null, updated_at timestamp(6), version bigint, otp_code varchar(10), sigla varchar(10) not null unique, telefone_autorizacao varchar(20) not null, nif varchar(50) not null unique, created_by varchar(100), modified_by varchar(100), nome varchar(150) not null, url_logo varchar(500), primary key (id));
create table itens_pedido (preco_unitario numeric(10,2) not null, quantidade integer not null check (quantidade>=1), subtotal numeric(10,2) not null, created_at timestamp(6) not null, id bigserial not null, pedido_id bigint, produto_id bigint not null, sub_pedido_id bigint not null, updated_at timestamp(6), version bigint, created_by varchar(100), modified_by varchar(100), observacoes varchar(500), primary key (id));
create table mesas (ativa boolean not null, capacidade integer, numero integer, created_at timestamp(6) not null, id bigserial not null, instituicao_id bigint, unidade_atendimento_id bigint not null, updated_at timestamp(6), version bigint, tipo varchar(30) not null check (tipo in ('MESA_FISICA','QUARTO','AREA_EVENTO','ESPACO_LOUNGE','VIRTUAL')), created_by varchar(100), modified_by varchar(100), qr_code varchar(100) unique, referencia varchar(100) not null, primary key (id));
create table pagamento_event_log (id bigserial not null, pagamento_id bigint, pedido_id bigint, timestamp timestamp(6) not null, ip varchar(50), role varchar(50) not null, tipo_evento varchar(50) not null check (tipo_evento in ('PAGAMENTO_CRIADO','CONFIRMACAO_PAGAMENTO','CALLBACK_RECEBIDO','AUTORIZACAO_POS_PAGO','NEGACAO_POS_PAGO','ESTORNO_MANUAL','ESTORNO_AUTOMATICO','POLITICA_POS_PAGO_ATIVADA','POLITICA_POS_PAGO_DESATIVADA','RECARGA_FUNDO','PAGAMENTO_FALHOU')), usuario varchar(100) not null, motivo varchar(500), dados_adicionais TEXT, primary key (id));
create table pagamentos_gateway (amount numeric(10,2) not null, cliente_id bigint, confirmed_at timestamp(6), created_at timestamp(6) not null, fundo_consumo_id bigint, id bigserial not null, pedido_id bigint, updated_at timestamp(6), version bigint, entidade varchar(10), external_reference varchar(15) unique, metodo varchar(20) check (metodo in ('GPO','REF')), referencia varchar(20), status varchar(20) not null check (status in ('PENDENTE','CONFIRMADO','FALHOU','ESTORNADO')), tipo_pagamento varchar(20) not null check (tipo_pagamento in ('PRE_PAGO','POS_PAGO')), created_by varchar(100), gateway_charge_id varchar(100), modified_by varchar(100), observacoes varchar(500), gateway_response TEXT, primary key (id));
