create table pedidos (total numeric(10,2), created_at timestamp(6) not null, id bigserial not null, pago_em timestamp(6), sessao_consumo_id bigint not null, updated_at timestamp(6), version bigint, status varchar(20) not null check (status in ('CRIADO','EM_ANDAMENTO','FINALIZADO','CANCELADO')), status_financeiro varchar(20) not null check (status_financeiro in ('NAO_PAGO','PAGO','ESTORNADO')), tipo_pagamento varchar(20) not null check (tipo_pagamento in ('PRE_PAGO','POS_PAGO')), created_by varchar(100), modified_by varchar(100), observacoes varchar(500), numero varchar(255) not null unique, primary key (id));
create table planos (ativo boolean not null, max_dispositivos integer not null, max_instituicoes integer not null, max_produtos integer not null, max_qr_codes integer not null, max_unidades_atendimento integer not null, max_usuarios integer not null, permite_multi_instituicao boolean not null, permite_offline boolean not null, permite_pedidos_qr boolean not null, permite_pos boolean not null, preco_mensal numeric(12,2) not null, created_at timestamp(6) not null, id bigserial not null, updated_at timestamp(6), version bigint, codigo varchar(30) not null unique, created_by varchar(100), modified_by varchar(100), nome varchar(120) not null, descricao TEXT, primary key (id));
